const seen = new Set();
const now = Date.now();
const NEWS_MAX_AGE_HOURS = 24;
const NEWS_MAX_ARTICLES = 30;
const maxAgeMs = NEWS_MAX_AGE_HOURS * 60 * 60 * 1000;
return items
  .map((item) => {
    const publishedRaw = item.json.isoDate || item.json.pubDate || item.json.published || item.json.date || '';
    const publishedAt = publishedRaw ? new Date(publishedRaw) : new Date();
    const title = String(item.json.title || '').trim();
    const link = String(item.json.link || item.json.guid || '').trim();
    const summary = String(item.json.contentSnippet || item.json.content || item.json.description || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
    return { json: { title, link, summary, publishedAt: publishedAt.toISOString(), source: item.json.creator || item.json['dc:creator'] || new URL(link || 'https://unknown.local').hostname } };
  })
  .filter((item) => item.json.title && item.json.link)
  .filter((item) => {
    const key = item.json.link.toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .filter((item) => now - new Date(item.json.publishedAt).getTime() <= maxAgeMs)
  .slice(0, NEWS_MAX_ARTICLES);

const parseCsv = (csv) => {
  const [headerLine, ...lines] = String(csv || '').split(/\r?\n/).filter(Boolean);
  const headers = headerLine.split(',').map((h) => h.trim().replace(/^\"|\"$/g, ''));
  return lines.map((line) => {
    const cols = line.match(/(\"[^\"]*\"|[^,]+)/g) || [];
    const row = {};
    headers.forEach((h, i) => row[h] = String(cols[i] || '').replace(/^\"|\"$/g, '').trim());
    return row;
  });
};

const nseCsv = items.find((item) => typeof item.json.data === 'string')?.json.data || items.find((item) => typeof item.json === 'string')?.json || '';
const companies = parseCsv(nseCsv).map((row) => ({
  symbol: row.SYMBOL,
  name: row.NAME_OF_COMPANY,
  series: row.SERIES
})).filter((row) => row.symbol && row.name && row.series === 'EQ');

const companyTerms = companies.flatMap((company) => {
  const cleanName = company.name.replace(/\b(LIMITED|LTD|PRIVATE|PVT|INDIA|THE)\b/gi, '').replace(/[^A-Z0-9 ]/gi, ' ').replace(/\s+/g, ' ').trim();
  return [company.symbol, cleanName].filter((term) => term && term.length >= 3).map((term) => ({ term: term.toUpperCase(), company }));
});

return items
  .filter((item) => item.json.title && item.json.link)
  .map((item) => {
    const haystack = `${item.json.title} ${item.json.summary}`.toUpperCase();
    const matches = [];
    for (const { term, company } of companyTerms) {
      const escaped = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      if (new RegExp(`(^|[^A-Z0-9])${escaped}([^A-Z0-9]|$)`).test(haystack)) {
        if (!matches.some((m) => m.symbol === company.symbol)) matches.push(company);
      }
      if (matches.length >= 5) break;
    }
    return { json: { ...item.json, nseMatches: matches } };
  })
  .filter((item) => item.json.nseMatches.length > 0);

