const rows = [];
for (const item of items) {
  const payload = item.json.message?.content || item.json.text || item.json;
  const parsed = typeof payload === 'string' ? JSON.parse(payload) : payload;
  for (const row of parsed.items || []) rows.push(row);
}
const unique = Array.from(new Map(rows.map((row) => [`${row.nseSymbol}-${row.sourceUrl}`, row])).values());
if (!unique.length) return [];
const today = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', dateStyle: 'medium', timeStyle: 'short' });
const icon = { Positive: '🟢', Negative: '🔴', Neutral: '⚪', Mixed: '🟡' };
const message = [
  `🇮🇳 *Indian NSE Stock News Impact Digest*`,
  `_Generated: ${today} IST_`,
  '',
  ...unique.map((row, index) => [
    `*${index + 1}. ${row.companyName} (${row.nseSymbol})*`,
    `📰 ${row.newsDescription}`,
    `${icon[row.impact] || '⚪'} *Impact:* ${row.impact} — ${row.impactReason}`,
    `🎯 Confidence: ${row.confidence}`,
    `🔗 ${row.sourceUrl}`
  ].join('\n'))
].join('\n\n');
return [{ json: { message, count: unique.length, items: unique } }];
